// LoadRace loads the raceGrid's Race into the .R struct
func (os RaceGridSlice) LoadRace(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	races, err := os.Race(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Race = nil
		o.R.Loaded.Race = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	raceGridByKey := make(map[int32][]*RaceGrid, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		raceGridByKey[o.RaceID] = append(raceGridByKey[o.RaceID], o)
	}

	for _, rel := range races {

		owners, ok := raceGridByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.Race != nil {
				continue
			}

			rel.R.RaceGrids = append(rel.R.RaceGrids, o)

			o.R.Race = rel

		}
	}

	return nil
}

